class TestREQ002ProductAPI:

    @pytest.mark.positive
    @pytest.mark.api
    def test_TC_REQ_002_01_positive_paginated_listing(self, client):
        """
        TC-REQ-002-01 [positive]
        Product listing returns paginated results with all required fields
        """
        # Arrange
        params = {"page": 1, "per_page": 10}
        required_fields = ["id", "name", "description", "price", "stock_quantity", "category"]

        # Act
        response = client.get("/products", params=params)

        # Assert
        assert response.status_code == 200
        data = response.json()
        assert "products" in data
        assert len(data["products"]) <= 10
        
        # Verify all required fields are present
        for product in data["products"]:
            for field in required_fields:
                assert field in product, f"Field {field} missing from product"

        # Verify response time
        assert response.elapsed.total_seconds() < 0.2

