# ── Performance Test ────────────────────────────────
class ProductListingUser(HttpUser):
    wait_time = between(1, 2)
    host = BASE_URL

    @task
    def get_products(self):
        with self.client.get(
            "/products",
            params={"page": 1, "per_page": 10},
            catch_response=True
        ) as response:
            if response.elapsed.total_seconds() > 0.2:
                response.failure("Response took too long")
            elif response.status_code != 200:
                response.failure("Wrong status code")
            else:
                response.success()

