# ── UI Tests ────────────────────────────────────────
class TestREQ002ProductUI:

    @pytest.mark.ui
    @pytest.mark.positive
    def test_product_listing_display(self, browser_page):
        """
        Verify product listing is displayed correctly in UI
        """
        # Arrange
        page = browser_page
        page.goto(f"{BASE_URL}/products")
        page.wait_for_load_state("networkidle")

        # Act & Assert
        product_grid = page.locator(".product-grid")
        expect(product_grid).to_be_visible()
        
        # Check pagination
        expect(page.get_by_role("navigation", name="pagination")).to_be_visible()
        
        # Check product cards
        products = page.locator(".product-card").all()
        for product in products:
            expect(product.locator(".product-name")).to_be_visible()
            expect(product.locator(".product-price")).to_be_visible()
            
            # Check if out of stock products are marked
            stock_status = product.locator(".stock-status")
            if stock_status.text_content() == "Out of Stock":
                expect(stock_status).to_have_class("out-of-stock")

        page.screenshot(path="screenshots/product_listing.png")
